package io.fluxora.platform.model;

/** 平台统一模型实体；不包含上游通道、凭证或任何供应商私有信息。 */
public class PlatformModel {
    private Long id; private String code; private String displayName; private String description; private String modelType; private String tags; private boolean supportsStreaming; private boolean supportsTools; private boolean supportsVision; private boolean supportsCache; private Long contextLength; private Long maxOutputLength; private boolean enabled; private Long createdBy; private Long updatedBy;
    public Long getId(){return id;} public void setId(Long v){id=v;} public String getCode(){return code;} public void setCode(String v){code=v;} public String getDisplayName(){return displayName;} public void setDisplayName(String v){displayName=v;} public String getDescription(){return description;} public void setDescription(String v){description=v;} public String getModelType(){return modelType;} public void setModelType(String v){modelType=v;} public String getTags(){return tags;} public void setTags(String v){tags=v;} public boolean isSupportsStreaming(){return supportsStreaming;} public void setSupportsStreaming(boolean v){supportsStreaming=v;} public boolean isSupportsTools(){return supportsTools;} public void setSupportsTools(boolean v){supportsTools=v;} public boolean isSupportsVision(){return supportsVision;} public void setSupportsVision(boolean v){supportsVision=v;} public boolean isSupportsCache(){return supportsCache;} public void setSupportsCache(boolean v){supportsCache=v;} public Long getContextLength(){return contextLength;} public void setContextLength(Long v){contextLength=v;} public Long getMaxOutputLength(){return maxOutputLength;} public void setMaxOutputLength(Long v){maxOutputLength=v;} public boolean isEnabled(){return enabled;} public void setEnabled(boolean v){enabled=v;} public Long getCreatedBy(){return createdBy;} public void setCreatedBy(Long v){createdBy=v;} public Long getUpdatedBy(){return updatedBy;} public void setUpdatedBy(Long v){updatedBy=v;}
}
